#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct generation_slot { int value; unsigned generation; int occupied; };

static int evidence_cmem_quarantine_generation_defense_ro6xe0(const struct generation_slot *slot, unsigned handle_generation, int *value) {
  if (slot == NULL || value == NULL || !slot->occupied) return 0;
  if (slot->generation != handle_generation) return 0;
  *value = slot->value;
  return 1;
}

int main(void) {
  struct generation_slot slot = { 10, 3u, 1 };
  int value = 0;
  int stale = evidence_cmem_quarantine_generation_defense_ro6xe0(&slot, 2u, &value);
  int current = evidence_cmem_quarantine_generation_defense_ro6xe0(&slot, 3u, &value);
  int invariant = !stale && current && value == 10;
  printf("generation value=%d invariant=%d\n", value, invariant);
  return invariant ? 0 : 1;
}
